=== Dockerfile ===
FROM php:8.1-apache
COPY . /var/www/html/
RUN docker-php-ext-install mysqli && docker-php-ext-enable mysqli
RUN apt-get update && apt-get install -y libpng-dev libjpeg-dev libfreetype6-dev \
    && docker-php-ext-configure gd --with-freetype --with-jpeg \
    && docker-php-ext-install gd
COPY ./php.ini /usr/local/etc/php/
EXPOSE 80

=== php.ini ===
display_errors = Off
log_errors = On
error_log = /var/log/php_errors.log
upload_max_filesize = 2M
post_max_size = 8M

=== .env ===
DB_HOST=localhost
DB_USER=root
DB_PASS=password
DB_NAME=mydatabase

=== db.php ===
<?php
$dotenv = Dotenv\Dotenv::createImmutable(__DIR__);
$dotenv->load();

$mysqli = new mysqli($_ENV['DB_HOST'], $_ENV['DB_USER'], $_ENV['DB_PASS'], $_ENV['DB_NAME']);

if ($mysqli->connect_error) {
    die("Connection failed: " . $mysqli->connect_error);
}
?>

=== register.php ===
<?php
require 'db.php';

if ($_SERVER['REQUEST_METHOD'] == 'POST') {
    $username = trim($_POST['username']);
    $password = trim($_POST['password']);

    if (empty($username) || empty($password)) {
        die('Username and password are required.');
    }

    $stmt = $mysqli->prepare("INSERT INTO users (username, password) VALUES (?, ?)");
    $hashed_password = password_hash($password, PASSWORD_BCRYPT);
    $stmt->bind_param("ss", $username, $hashed_password);

    if ($stmt->execute()) {
        echo "Registration successful.";
    } else {
        echo "Error: " . $stmt->error;
    }

    $stmt->close();
}
?>

=== login.php ===
<?php
session_start();
require 'db.php';

if ($_SERVER['REQUEST_METHOD'] == 'POST') {
    $username = trim($_POST['username']);
    $password = trim($_POST['password']);

    if (empty($username) || empty($password)) {
        die('Username and password are required.');
    }

    $stmt = $mysqli->prepare("SELECT password FROM users WHERE username = ?");
    $stmt->bind_param("s", $username);
    $stmt->execute();
    $stmt->store_result();

    if ($stmt->num_rows > 0) {
        $stmt->bind_result($hashed_password);
        $stmt->fetch();

        if (password_verify($password, $hashed_password)) {
            $_SESSION['username'] = $username;
            echo "Login successful.";
        } else {
            echo "Invalid credentials.";
        }
    } else {
        echo "Invalid credentials.";
    }

    $stmt->close();
}
?>

=== logout.php ===
<?php
session_start();
session_destroy();
header("Location: login.php");
?>

=== upload.php ===
<?php
session_start();
require 'db.php';

if (!isset($_SESSION['username'])) {
    die('You must be logged in to upload files.');
}

if ($_SERVER['REQUEST_METHOD'] == 'POST' && isset($_FILES['file'])) {
    $file = $_FILES['file'];

    if ($file['error'] !== UPLOAD_ERR_OK) {
        die('File upload error.');
    }

    $allowed_types = ['image/jpeg', 'image/png'];
    if (!in_array($file['type'], $allowed_types)) {
        die('Invalid file type.');
    }

    $upload_dir = 'uploads/';
    move_uploaded_file($file['tmp_name'], $upload_dir . basename($file['name']));
    echo "File uploaded successfully.";
}
?>

=== index.php ===
<?php
session_start();
?>
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>PHP Web App</title>
</head>
<body>
    <h1>Welcome to the PHP Web App</h1>
    <?php if (isset($_SESSION['username'])): ?>
        <p>Hello, <?php echo htmlspecialchars($_SESSION['username']); ?>!</p>
        <a href="logout.php">Logout</a>
    <?php else: ?>
        <a href="login.php">Login</a>
        <a href="register.php">Register</a>
    <?php endif; ?>
    <form action="upload.php" method="post" enctype="multipart/form-data">
        <input type="file" name="file" required>
        <button type="submit">Upload</button>
    </form>
</body>
</html>

=== create_users_table.sql ===
CREATE TABLE users (
    id INT AUTO_INCREMENT PRIMARY KEY,
    username VARCHAR(50) NOT NULL UNIQUE,
    password VARCHAR(255) NOT NULL
);

=== README.md ===
# PHP Web Application

## Setup Instructions

1. Clone the repository.
2. Create a `.env` file based on the `.env` template provided.
3. Build the Docker image:
   ```
   docker build -t php-web-app .
   ```
4. Run the Docker container:
   ```
   docker run -d -p 80:80 --env-file .env php-web-app
   ```
5. Access the application at `http://localhost`.

6. Run the SQL script `create_users_table.sql` to set up the database.

## Features
- User registration
- User login
- File upload
- Secure coding practices implemented

## Security
- Passwords are hashed using bcrypt.
- Input validation and sanitization are performed.
- CSRF protection should be implemented in production (not shown in this example).
- Secure cookie flags should be set in production (not shown in this example).
